def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 1, -2):
                for b in range(1, a + 4):
                    term = ((ratio - a) ** 6) / (b ** 1.1 + a) * np.sin(ratio * b / (a + 2))
                    priority += term * np.tanh(ratio / (b + 0.3))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.7)) ** 2.0
            if bin_cap < item * 0.3:
                priority += np.log1p(item ** 3 / (bin_cap + 1)) * 7
        elif 5 < ratio <= 8:
            for x in range(1, int(ratio) + 5):
                for y in range(1, x + 4):
                    val = ((ratio - x) ** 4) * np.cos(ratio * y * 1.3) / (y ** 1.5 + x)
                    priority += np.sinh(val) * 1.5
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3.5
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 6
        elif 2 < ratio <= 5:
            s = 0
            for n in range(1, 15):
                s += ((ratio - 2) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.1)
            priority = s * np.sin(6 * ratio) - np.log(ratio) * 8 + np.tanh(5 - ratio) * 2.5
            if bin_cap < item * 1.2:
                priority += np.sqrt(bin_cap / (item + 0.7)) * 5
        elif 1 <= ratio <= 2:
            s = 0
            for m in range(1, 20):
                s += ((2 - ratio) ** m) / (m * 2.2) * np.sin(m * ratio * 2)
            if bin_cap < item:
                penalty = np.exp(-bin_cap / (item + 0.1)) * 6
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2.1 / (ratio + 0.1))
            for k in range(1, 6):
                priority += np.sin(k * ratio * i * 1.3) * ((ratio - 1) ** k) / (k + 0.7)
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3.7) * np.cos(j * item * 1.4)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for z in range(1, 7):
                priority += ((1 - ratio) ** z) * np.sin(z * item * 1.8) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 14):
                s += ((0.5 - ratio) ** w) / (w * 2.7) * np.cos(w * ratio * 2.1)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for v in range(1, 9):
                priority += ((0.5 - ratio) ** v) / (v * 7) * np.cos(item * v * 1.3)
        else:
            s = 0
            for u in range(1, 12):
                s += ((0.2 - ratio) ** u) / (u * 6) * np.sin(u * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.6) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for t in range(1, 10):
                priority += ((0.2 - ratio) ** t) / (t * 8) * np.cos(item * t * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 7
            priority -= np.sin(ratio * i * 2.0) * 1.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 6
            priority += np.cos(ratio * i * 1.7) * 1.3
        for idx in range(1, 6):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.5) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.9) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.9) * 0.8
        if bin_cap % 2 == 0:
            priority += np.tanh(ratio * bin_cap / (item + 1)) * 1.1
        else:
            priority -= np.tanh(ratio * bin_cap / (item + 1)) * 1.1
        priorities[i] = priority
    return priorities
